input.command:
powershell << 'PS_SCRIPT'
$MSBuild = "C:\Program Files (x86)\Microsoft Visual Studio\2022\BuildTools\MSBuild\Current\Bin\MSBuild.exe"
$TargetDir = "C:\Users\Administrator\Desktop\DSC CHINA NX4\exe"
$projects = @(
    @{
        path = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C FRT\NX4C FRT\JA01"
        proj = "FRT JA01.vbproj"
        output = "NX4C_FRT_JA01(20260313).exe"
    },
    @{
        path = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C FRT\NX4C FRT\JA02"
        proj = "FRT JA02.vbproj"
        output = "NX4C_FRT_JA02(20260313).exe"
    },
    @{
        path = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C FRT\NX4C FRT\JA03"
        proj = "FRT JA03.vbproj"
        output = "NX4C_FRT_JA03(20260313).exe"
    },
    @{
        path = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C FRT\NX4C FRT\JA04"
        proj = "FRT JA04.vbproj"
        output = "NX4C_FRT_JA04(20260313).exe"
    },
    @{
        path = "C:\Users\Administrator\Desktop\DSC CHINA NX4\NX4C FRT\NX4C FRT\SERVER SEARCH"
        proj = "SERVEr Search.vbproj"
        output = "NX4C_FRT_SERVER_SEARCH(20260313).exe"
    }
)

foreach ($proj in $projects) {
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host "Building: $($proj.proj)" -ForegroundColor Cyan
    Write-Host "Path: $($proj.path)" -ForegroundColor Cyan

    Push-Location $proj.path

    & $MSBuild $proj.proj /p:Configuration=Release /p:Platform=AnyCPU

    if ($LASTEXITCODE -eq 0) {
        Write-Host "Build SUCCESSFUL" -ForegroundColor Green

        $exePath = ".\bin\Release\$($proj.proj -replace '.vbproj', '.exe')"

        if (Test-Path $exePath) {
            Copy-Item $exePath "$TargetDir\$($proj.output)" -Force
            Write-Host "COPIED: $exePath -> $TargetDir\$($proj.output)" -ForegroundColor Green
        } else {
            Write-Host "ERROR: EXE not found at $exePath" -ForegroundColor Red
            Get-ChildItem ".\bin\Release\" -Filter "*.exe" 2>/dev/null | ForEach-Object {
                Write-Host "  Found: $($_.FullName)" -ForegroundColor Yellow
            }
        }
    } else {
        Write-Host "Build FAILED with exit code $LASTEXITCODE" -ForegroundColor Red
    }

    Pop-Location
    Write-Host ""
}

Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Build Summary:" -ForegroundColor Cyan
Get-ChildItem $TargetDir -Filter "NX4C_FRT_*.exe" | ForEach-Object {
    Write-Host "  $($_.Name)" -ForegroundColor Green
}
PS_SCRIPT
